#include <iostream>
const int N = 10;
int ch[N][N][N];
int main() {
    for (int x = 0; x < N; x++)
    for (int y = 0; y < N; y++)
    for (int z = 0; z < N; z++)
    if (x == 0 && y == 0 && z == 0)
    ch[x][y][z] = 1;
    else {
        if (x > 0)
        ch[x][y][z] += ch[x - 1][y][z];
        if (y > 0)
        ch[x][y][z] += ch[x][y - 1][z];
        if (z > 0)
        ch[x][y][z] += ch[x][y][z - 1];
    }
    std::cout << ch[1][2][3] << std::endl;
    return 0;
}
```

下面count_triple函数的时间复杂度为( )。

```cpp
int gcd(int a, int b) {
    if (a == 0)
    return b;
    return gcd(b % a, a);
}
int count_triple(int n) {
    int cnt = 0;
    for (int v = 1; v * v * 4 <= n; v++)
    for (int u = v + 1; u * (u + v) * 2 <= n; u += 2)
    if (gcd(u, v) == 1) {
        int a = u * u - v * v;
        int b = u * v * 2;
        int c = u * u + v * v;
        cnt += n / (a + b + c);
    }
    return cnt;
}
```

